code = """import json
import re

# Load previous results
ema_results_raw = locals()['var_functions.execute_python:84']
cpc_titles_raw = locals()['var_functions.query_db:88']

# Process EMA results
ema_results = ema_results_raw['ema_sample']
cpc_codes = [item[0] for item in ema_results]
best_years = [item[1] for item in ema_results]
ema_values = [item[2] for item in ema_results]

# Get CPC titles dictionary
cpc_titles = {}
for item in cpc_titles_raw:
    if 'symbol' in item and 'titleFull' in item:
        cpc_titles[item['symbol']] = item['titleFull']

# Filter for non-zero EMA and create final results
final_results = []
for cpc_code, year, ema_val in zip(cpc_codes, best_years, ema_values):
    if ema_val > 0:
        title = cpc_titles.get(cpc_code, 'Title not found')
        final_results.append({
            'cpc_group_code': cpc_code,
            'full_title': title,
            'best_year': year,
            'max_ema': ema_val
        })

# Sort by EMA value descending
final_results.sort(key=lambda x: x['max_ema'], reverse=True)

print('Found %d CPC technology areas with EMA > 0' % len(final_results))
print('\nTop CPC Technology Areas in Germany (H2 2019 grants):')
for i, result in enumerate(final_results[:10], 1):
    print('%d. %s - %s' % (i, result['cpc_group_code'], result['full_title'][:60]))
    print('   Best Year: %d, Max EMA: %.2f\n' % (result['best_year'], result['max_ema']))

output = {
    'total_technology_areas': len(final_results),
    'top_results': final_results[:10]
}

print('__RESULT__:')
print(json.dumps(output, ensure_ascii=False))"""

